1	interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface QuoteStep {
9	  op: "quote";
10	  items: Item[];
11	}
12	
13	interface Damage {
14	  itemType: string;
15	  amount: number;
16	}
17	
18	interface ClaimStep {
19	  op: "claim";
20	  policy: number;
21	  incident: { cause: string; damages: Damage[] };
22	}
23	
24	type Step = QuoteStep | ClaimStep;
25	
26	interface Scenario {
27	  customer: { yearsWithMHPCO: number };
28	  steps: Step[];
29	}
30	
31	const BASE_PREMIUM: Record<string, number> = {
32	  sword: 100,
33	  amulet: 60,
34	  staff: 80,
35	  potion: 40,
36	  rune: 25,
37	  moonstone: 25,
38	};
39	
40	const INSURANCE_VALUE: Record<string, number> = {
41	  sword: 1000,
42	  amulet: 600,
43	  staff: 800,
44	  potion: 400,
45	  rune: 250,
46	  moonstone: 250,
47	};
48	
49	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
50	const BLOCK_SIZE = 3;
51	const BLOCK_PREMIUM = 60;
52	const DEDUCTIBLE = 100;
53	const CAP_MULTIPLIER = 2;
54	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
55	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
56	const FULL_REIMBURSEMENT_RATE = 1;
57	
58	const FIRST_INSURANCE_SURCHARGE = 0.1;
59	const CURSE_SURCHARGE = 0.5;
60	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
61	const HIGH_ENCHANTMENT_THRESHOLD = 5;
62	const LOYALTY_DISCOUNT = 0.2;
63	const LOYALTY_THRESHOLD_YEARS = 2;
64	const FOLLOWUP_DISCOUNT = 0.15;
65	const PROCESSING_FEE = 5;
66	
67	// Premiums are rounded up. We strip floating-point noise (e.g. 197.49999999)
68	// before rounding so that arithmetic artefacts don't push the result up a whole Gold.
69	const roundPremiumUp = (amount: number): number => Math.ceil(Number(amount.toFixed(6)));
70	
71	// A block applies only to a group of exactly BLOCK_SIZE alike components,
72	// priced at BLOCK_PREMIUM; any other count is priced individually.
73	const componentBasePremium = (count: number, perComponent: number): number => {
74	  if (count === BLOCK_SIZE) return BLOCK_PREMIUM;
75	  return count * perComponent;
76	};
77	
78	const sum = (amounts: number[]): number => amounts.reduce((acc, amount) => acc + amount, 0);
79	
80	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
81	const isMainItem = (item: Item): boolean => !isComponent(item);
82	
83	const countByType = (items: Item[]): Record<string, number> => {
84	  const counts: Record<string, number> = {};
85	  for (const item of items) {
86	    counts[item.type] = (counts[item.type] ?? 0) + 1;
87	  }
88	  return counts;
89	};
90	
91	// A surcharge rate is an additive percentage applied on top of a base premium.
92	const applySurcharge = (base: number, rate: number): number => base * (1 + rate);
93	
94	// A conditional rate: the given percentage when its condition holds, else 0.
95	// Used for both item surcharges and policy-wide discounts.
96	const rateWhen = (applies: boolean, rate: number): number => (applies ? rate : 0);
97	
98	// Item-specific surcharges are additive percentages of the item's base premium.
99	// First insurance applies to every item; the others only when their condition holds.
100	const itemSurchargeRate = (item: Item): number =>
101	  sum([
102	    FIRST_INSURANCE_SURCHARGE,
103	    rateWhen(item.cursed === true, CURSE_SURCHARGE),
104	    rateWhen((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD, HIGH_ENCHANTMENT_SURCHARGE),
105	  ]);
106	
107	const mainItemPremium = (item: Item): number =>
108	  applySurcharge(BASE_PREMIUM[item.type], itemSurchargeRate(item));
109	
110	const componentGroupBases = (items: Item[]): number[] =>
111	  Object.entries(countByType(items.filter(isComponent))).map(([type, count]) =>
112	    componentBasePremium(count, BASE_PREMIUM[type]),
113	  );
114	
115	// Sum of item base premiums with block pricing but no surcharges; the basis
116	// for policy-wide modifiers (loyalty, follow-up).
117	const policyBasePremium = (items: Item[]): number =>
118	  sum(items.filter(isMainItem).map((item) => BASE_PREMIUM[item.type])) +
119	  sum(componentGroupBases(items));
120	
121	// Sum of item premiums including item-specific surcharges (curse, high
122	// enchantment, first insurance).
123	const itemsPremium = (items: Item[]): number => {
124	  const mainItemsPremium = sum(items.filter(isMainItem).map(mainItemPremium));
125	  const componentsPremium = sum(
126	    componentGroupBases(items).map((base) => applySurcharge(base, FIRST_INSURANCE_SURCHARGE)),
127	  );
128	  return mainItemsPremium + componentsPremium;
129	};
130	
131	// Policy-wide discounts are a rate applied to the unmodified policy base.
132	// Loyalty is one such discount; the follow-up-contract discount will be another.
133	const policyWideDiscount = (rate: number, policyBase: number): number => rate * policyBase;
134	
135	const loyaltyDiscountRate = (yearsWithMHPCO: number): number =>
136	  rateWhen(yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS, LOYALTY_DISCOUNT);
137	
138	const quotePremium = (items: Item[], yearsWithMHPCO: number, isFollowup: boolean): number => {
139	  const surcharged = itemsPremium(items);
140	  const policyBase = policyBasePremium(items);
141	  const discountRate = loyaltyDiscountRate(yearsWithMHPCO) + rateWhen(isFollowup, FOLLOWUP_DISCOUNT);
142	  const discount = policyWideDiscount(discountRate, policyBase);
143	  return roundPremiumUp(surcharged - discount + PROCESSING_FEE);
144	};
145	
146	const insuranceSum = (items: Item[]): number =>
147	  sum(items.map((item) => INSURANCE_VALUE[item.type]));
148	
149	const findInsuredItem = (policyItems: Item[], itemType: string): Item | undefined =>
150	  policyItems.find((item) => item.type === itemType);
151	
152	const isHighlyEnchanted = (item: Item | undefined): boolean =>
153	  (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
154	
155	// The damaged item's traits decide what fraction of the damage is reimbursed
156	// before the deductible. Clauses are checked in priority order, so the first
157	// matching one wins; a full reimbursement applies when none does.
158	const reimbursementRate = (item: Item | undefined): number => {
159	  if (isHighlyEnchanted(item)) return HIGH_ENCHANTMENT_REIMBURSEMENT_RATE;
160	  return FULL_REIMBURSEMENT_RATE;
161	};
162	
163	const reimbursement = (item: Item | undefined, amount: number): number =>
164	  amount * reimbursementRate(item);
165	
166	const damagePayout = (damage: Damage, item: Item | undefined): number =>
167	  Math.max(0, reimbursement(item, damage.amount) - DEDUCTIBLE);
168	
169	// The uncapped payout an incident would pay before the policy's remaining cap
170	// is applied: each damage reimbursed per its item's clause, less the deductible.
171	const incidentPayout = (policyItems: Item[], incident: ClaimStep["incident"]): number =>
172	  sum(
173	    incident.damages.map((damage) =>
174	      damagePayout(damage, findInsuredItem(policyItems, damage.itemType)),
175	    ),
176	  );
177	
178	interface Policy {
179	  items: Item[];
180	  remainingCap: number;
181	}
182	
183	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
184	  const { yearsWithMHPCO } = scenario.customer;
185	  const policies: Record<number, Policy> = {};
186	  let quoteCount = 0;
187	
188	  const handleQuote = (step: QuoteStep, index: number): { premium: number } => {
189	    policies[index] = {
190	      items: step.items,
191	      remainingCap: CAP_MULTIPLIER * insuranceSum(step.items),
192	    };
193	    const isFollowup = quoteCount > 0;
194	    quoteCount += 1;
195	    return { premium: quotePremium(step.items, yearsWithMHPCO, isFollowup) };
196	  };
197	
198	  const handleClaim = (step: ClaimStep): { payout: number; remainingCap: number } => {
199	    const policy = policies[step.policy];
200	    const payout = Math.min(incidentPayout(policy.items, step.incident), policy.remainingCap);
201	    policy.remainingCap -= payout;
202	    return { payout, remainingCap: policy.remainingCap };
203	  };
204	
205	  const results = scenario.steps.map((step, index) =>
206	    step.op === "claim" ? handleClaim(step) : handleQuote(step, index),
207	  );
208	
209	  return { results };
210	};
